+    let mut results = Vec::new();
+
+    for run in 0..2 {
+        let mut mgr = AsyncTaskManager::new();
+
+        // Fixed sequence of operations
+        for _ in 0..10 {
+            mgr.update(&press(KeyCode::Char('n')));
