+            if let Some(cell) = frame.buffer.get(x, y)
+                && let Some(ch) = cell.content.as_char()
+            {
+                text.push(ch);
+            } else {
+                text.push(' ');
+            }
+        }
+        text.push('\n');
+    }
+    text
+}
